import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate, Link } from 'react-router-dom';

function RegisterPage() {
  const [formData, setFormData] = useState({
    email: '',
    lastName: '',
    firstName: '',
    password: '',
    confirmPassword: ''
  });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
    // Очищаем ошибки при вводе
    if (error) setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // Валидация
    if (formData.password !== formData.confirmPassword) {
      setError('Пароли не совпадают');
      return;
    }
    
    if (formData.password.length < 6) {
      setError('Пароль должен содержать минимум 6 символов');
      return;
    }
    
    setLoading(true);
    setError('');
    
    try {
      await axios.post('http://localhost:8000/api/register/', {
        username: formData.email,  // используем email как username
        password: formData.password,
        first_name: formData.firstName,
        last_name: formData.lastName,
        email: formData.email
      });
      
      setSuccess('Регистрация успешна! Перенаправляем на вход...');
      setTimeout(() => {
        navigate('/login');
      }, 2000);
    } catch (err) {
      setError('Ошибка регистрации. Возможно, такой email уже используется.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      minHeight: '80vh',
      padding: '20px'
    }}>
      <div className="card" style={{ maxWidth: 520, width: '100%', padding: 0, overflow: 'hidden' }}>
        {/* Заголовок */}
        <div style={{
          padding: '24px 32px',
          borderBottom: '1px solid var(--border-light)',
          backgroundColor: '#fafbfc'
        }}>
          <h2 style={{ fontSize: 24, marginBottom: 4 }}>Регистрация</h2>
          <p className="form-hint">Заполните данные для создания аккаунта</p>
        </div>
        
        {/* Форма */}
        <form onSubmit={handleSubmit} style={{ padding: '28px 32px' }}>
          {/* Код доступа / email секция */}
          <div style={{ marginBottom: 24 }}>
            <div style={{
              backgroundColor: '#f0f4ff',
              borderRadius: 'var(--radius-md)',
              padding: 16,
              marginBottom: 20
            }}>
              <h3 style={{ fontSize: 16, fontWeight: 600, marginBottom: 12, color: 'var(--accent)' }}>
                🔐 Данные для входа
              </h3>
              <div className="form-group">
                <label className="form-label">Электронная почта</label>
                <input
                  type="email"
                  name="email"
                  className="form-input"
                  placeholder="my_email@mail.com"
                  value={formData.email}
                  onChange={handleChange}
                  required
                />
                <span className="form-hint">Укажите email для восстановления доступа</span>
              </div>
              
              <div className="form-group">
                <label className="form-label">Пароль</label>
                <input
                  type="password"
                  name="password"
                  className="form-input"
                  placeholder="••••••••"
                  value={formData.password}
                  onChange={handleChange}
                  required
                />
                <span className="form-hint">Минимум 6 символов</span>
              </div>
              
              <div className="form-group">
                <label className="form-label">Подтверждение пароля</label>
                <input
                  type="password"
                  name="confirmPassword"
                  className="form-input"
                  placeholder="••••••••"
                  value={formData.confirmPassword}
                  onChange={handleChange}
                  required
                />
              </div>
            </div>
            
            {/* Прочие данные */}
            <div>
              <h3 style={{ fontSize: 16, fontWeight: 600, marginBottom: 12, color: 'var(--text-secondary)' }}>
                👤 Прочие данные
              </h3>
              
              <div className="form-group">
                <label className="form-label">Фамилия</label>
                <input
                  type="text"
                  name="lastName"
                  className="form-input"
                  placeholder="Ваша фамилия"
                  value={formData.lastName}
                  onChange={handleChange}
                />
              </div>
              
              <div className="form-group">
                <label className="form-label">Имя</label>
                <input
                  type="text"
                  name="firstName"
                  className="form-input"
                  placeholder="Ваше имя"
                  value={formData.firstName}
                  onChange={handleChange}
                />
              </div>
            </div>
          </div>
          
          {error && (
            <div style={{
              backgroundColor: '#fee2e2',
              color: 'var(--error)',
              padding: 12,
              borderRadius: 'var(--radius-md)',
              marginBottom: 20,
              fontSize: 14
            }}>
              {error}
            </div>
          )}
          
          {success && (
            <div style={{
              backgroundColor: '#d1fae5',
              color: 'var(--success)',
              padding: 12,
              borderRadius: 'var(--radius-md)',
              marginBottom: 20,
              fontSize: 14
            }}>
              {success}
            </div>
          )}
          
          <div style={{ display: 'flex', gap: 16, marginTop: 8 }}>
            <button
              type="submit"
              className="btn btn-primary"
              disabled={loading}
              style={{ flex: 1 }}
            >
              {loading ? 'Регистрация...' : 'Зарегистрироваться'}
            </button>
            <Link to="/login" className="btn btn-outline" style={{ textDecoration: 'none', textAlign: 'center', flex: 1 }}>
              Войти
            </Link>
          </div>
          
          <p style={{
            fontSize: 12,
            color: 'var(--text-hint)',
            textAlign: 'center',
            marginTop: 20,
            paddingTop: 16,
            borderTop: '1px solid var(--border-light)'
          }}>
            <span style={{ color: 'var(--error)' }}>*</span> поле, обязательное для заполнения
          </p>
        </form>
      </div>
    </div>
  );
}

export default RegisterPage;
